import{_ as a,o as e,c as i,e as l}from"./app-4cb4de65.js";const d={},h=l('<h1 id="高效运作-pmo" tabindex="-1"><a class="header-anchor" href="#高效运作-pmo" aria-hidden="true">#</a> 高效运作 PMO</h1><h2 id="pmo-价值的度量指标" tabindex="-1"><a class="header-anchor" href="#pmo-价值的度量指标" aria-hidden="true">#</a> PMO 价值的度量指标</h2><h3 id="关键指标" tabindex="-1"><a class="header-anchor" href="#关键指标" aria-hidden="true">#</a> 关键指标</h3><h4 id="人员价值增加-people-value-added-pva" tabindex="-1"><a class="header-anchor" href="#人员价值增加-people-value-added-pva" aria-hidden="true">#</a> 人员价值增加（People Value Added，PVA）</h4><p>人员价值增加体现在项目参与者在参与项目前后技能水平、工作效率、工作质量等方面，以及因此带来的该员工自身职业价值的提升。人员价值增加也体现在组织的整体技能水平和整体人员价值的提升。可采用的度量指标有平均每位项目成员每年所完成的项目金额等</p><h4 id="客户价值增加-customer-value-added-cva" tabindex="-1"><a class="header-anchor" href="#客户价值增加-customer-value-added-cva" aria-hidden="true">#</a> 客户价值增加（Customer Value Added，CVA）</h4><p>客户价值增加可以通过客户满意度调查的方法来获得。支付了同样的价格，如果项目做得不成功，客户得到的可能是布满缺陷的系统，这套系统不仅不能给客户的业务带来增长机会，反而成了让客户头疼的“置之无用、弃之可惜”的鸡肋；相反，如果项目做得成功，那么客户获得的是一套运行良好的系统，凭借这套系统，客户的业务可以得到显著的提升。因此，客户价值增加体现了客户支付的每单位货币所获取的实际价值。客户满意度调查可以反映客户对这种价值的感受。</p><h4 id="经济价值增加-economic-value-added-eva" tabindex="-1"><a class="header-anchor" href="#经济价值增加-economic-value-added-eva" aria-hidden="true">#</a> 经济价值增加（Economic Value Added，EVA）</h4><p>成功的项目可以给组织带来直接和间接的经济收益。对于客户项目来说，通过向客户提供有价值的项目产品，可以直接为公司赚取利润；对于内部项目来说，通过实施项目使得组织运作效率得到提升，间接地为组织贡献经济价值。如果项目管理得不好，项目中出现超支和延误，项目所交付的产品没有实现预期的功能，那么组织投资该项目的预期收益就不能实现。经济价值可以用项目收益、投资回报率、净现值、投资回收期、内部收益率等财务指标来度量。</p><h3 id="定量指标" tabindex="-1"><a class="header-anchor" href="#定量指标" aria-hidden="true">#</a> 定量指标</h3><ul><li>所有项目的营收增加</li><li>所有项目带来的新市场开发和客户数量增加</li><li>所有项目带来的成本降低</li><li>所有项目的净现值（NPV）</li><li>所有项目的投资回报率（ROI）</li><li>所有项目的内部收益率（IRR）</li><li>组织风险得以减少的程度</li><li>资源使用的数量，包括计划数量和实际数量</li><li>项目交付周期整体缩短的百分比</li><li>组织质量成本的变化</li></ul><h3 id="定性指标" tabindex="-1"><a class="header-anchor" href="#定性指标" aria-hidden="true">#</a> 定性指标</h3><ul><li>对战略的支持程度</li><li>对法律法规的符合性</li><li>客户满意度</li><li>市场美誉度</li><li>员工满意度</li></ul><h3 id="间接指标" tabindex="-1"><a class="header-anchor" href="#间接指标" aria-hidden="true">#</a> 间接指标</h3><ul><li>项目组合中红色、黄色、绿色项目占比</li><li>项目组合中交付成功、收益成功、战略成功的项目占比</li><li>PMP、PgMP 等认证人员在项目团队中的占比，以及在 PMO 成员中的占比</li><li>组织项目管理整体水平的提升，如 OPM3 级别的提升</li></ul><h2 id="项目环境下的-pmo" tabindex="-1"><a class="header-anchor" href="#项目环境下的-pmo" aria-hidden="true">#</a> 项目环境下的 PMO</h2><h3 id="评估组织启动敏捷方法的条件是否成熟" tabindex="-1"><a class="header-anchor" href="#评估组织启动敏捷方法的条件是否成熟" aria-hidden="true">#</a> 评估组织启动敏捷方法的条件是否成熟</h3><h4 id="对组织文化进行评估" tabindex="-1"><a class="header-anchor" href="#对组织文化进行评估" aria-hidden="true">#</a> 对组织文化进行评估</h4><ul><li>人们对待工作的态度 番茄计时器：有的人用来提醒自己需要开始工作了，有的人提醒自己工作时间太长了需要休息一下。 有发自内心的完成工作的紧迫感。</li><li>人们对待同事的态度 如果内核关系是竞争关系，就无法进行真正的知识分享。即使建立了知识分享系统和机制，也只是一种形式主义，人们应付差事，上传一些价值不大的文档资料。一个显性知识尚且管理不好的组织，隐形知识的分享更无从谈起。 组织可能需要从人事制度、激励制度等方面做出变革。</li><li>人们对待领导的态度 员工对待领导的态度主要取决于领导对待员工的态度。 开诚布公，积极进谏。</li><li>人们对待客户的态度 对待客户的态度需要从甲乙双方“对立”的关系，变成项目“一家人”的关系。合同或者协议中承诺的工作，应该保质保量地完成好，但是不要总是搬出合同来说事儿，而是要真正站到客户的角度，为客户着想，为客户解决问题，用自己的专业技能引领客户，帮助客户建立一个合理的、科学的、具有前瞻性的项目需求，并且最终实现这个需求，为客户创造收益。</li><li>人们对待自身利益的态度 员工需要为自己承诺的工作负责，既然承诺就要完成，不管是否需要加班。 组织应该担当起更多的责任，领导者更应该以身作则、身先士卒。 组织文化要在“无私奉献”和“锱铢必较”之间做出平衡。</li></ul><h4 id="对组织结构进行评估" tabindex="-1"><a class="header-anchor" href="#对组织结构进行评估" aria-hidden="true">#</a> 对组织结构进行评估</h4><p>为了适应敏捷方法，组织结构需要具有足够的灵活性。 《谁说大象不能跳舞》 敏捷环境需要的是一个全开放的、实时更新的资源库，这个资源库包含了公司的所有资源，也包含了外部的可用资源。只要项目需要，只要资源合适，项目经理就有权力获得资源组建团队，不论这个资源目前所处哪个部门，是组织内部的，还是外部的。 在采用了敏捷方法之后，组织需要和这些外部团体调整之前的工作关系，从甲方付费乙方干活的简单关系，转变为合作共创的长久依赖关系。实施敏捷方法，需要供应商和客户多方联动，PMO 需要向各方推广方法，宣讲好处，并切实告诉各方在实施敏捷方法后所需做出的思想上、行为上、工作流程上等方面的具体变化，以及各方相关部门和人员的角色职责调整。为此，PMO 需要担当一个敏捷方法的游说者。</p><h4 id="对项目团队进行评估" tabindex="-1"><a class="header-anchor" href="#对项目团队进行评估" aria-hidden="true">#</a> 对项目团队进行评估</h4><p>敏捷方法倡导自组织团队，他们认为最佳的设计和最佳的解决方案都出自自组织团队。所谓自组织团队，就是由团队成员自己做出决策，自己制订计划，自己承诺目标，自己执行工作，自己检查工作的完成情况，并根据情况自己进行纠正，最后自己交付产品，并且在交付之后对过程进行自我反思，从而实现持续改进。</p><ul><li>技术水平 所谓的 T 形人才，就是说每个成员需要对自己所负责的领域深扎下去，成为这方面的专家；同时还要横向掌握项目团队其他岗位所需要的能力。</li><li>价值观 PMO 要向团队宣讲敏捷价值观，并得到团队的真心认可。五大价值观 <ul><li>承诺：愿意对目标做出承诺</li><li>专注：把自己的心思和能力都用到所承诺的工作上去</li><li>开放：把项目中的一切开放给每个相关方看</li><li>尊重：每个人都有其独特的背景和经验，尊重任何人</li><li>勇气：有勇气做出承诺，履行承诺，接受别人的尊重</li></ul></li><li>建立团队成员之间的默契 对于一个自组织的团队而言，成员之间的默契是制胜的关键。 需要的是一支相互信任且有明确的共同目标的团队。 这一群人能够及时反应且迅速协调一致。 伟大的团队中，所有的成员都必须彼此信任，随着时间的推移，这些人会发现彼此的优点和缺点，这会使他们更加知道如何取长补短、协调一致，从而像一个整体一样去行动。 伟大的团队中，所有的成员都必须彼此信任，随着时间的推移，这些人会发现彼此的优点和缺点，这会使他们更加知道如何取长补短、协调一致，从而像一个整体一样去行动。</li></ul>',24),r=[h];function n(c,t){return e(),i("div",null,r)}const s=a(d,[["render",n],["__file","高效运作PMO.html.vue"]]);export{s as default};
